const now = new Date();
const today = now.toISOString().slice(0, 10);
const runId = `N8N-STOCK-REPACK-${Date.now()}`;
return [{ json: { runId, company: 'Thái Duy Digital', parentWarehouse: 'All Warehouses - TDD', postingDate: today, itemGroup: `${runId} Nhóm sản xuất`, rawWarehouseName: `${runId} Raw WH`, finishedWarehouseName: `${runId} Finished WH`, rawA: `${runId} Nguyên liệu A`, rawB: `${runId} Nguyên liệu B`, finished: `${runId} Thành phẩm đóng gói`, receiptRawA: 5, receiptRawB: 4, consumeRawA: 2, consumeRawB: 1, finishedQty: 1, rawARate: 30, rawBRate: 20, finishedRate: 80 } }];

const ctx = $node['Build Repack Context'].json;
const rawABin = $('Verify Repack Raw A Bin').all().map(i => i.json);
const rawBBin = $('Verify Repack Raw B Bin').all().map(i => i.json);
const finishedBin = $('Verify Repack Finished Bin').all().map(i => i.json);
const sleRows = $('Verify Repack SLE').all().map(i => i.json);
const receipt = $node['Submit Repack Raw Receipt'].json;
const repack = $node['Submit Repack Stock Entry'].json;
const rawAQty = Number(rawABin[0]?.actual_qty ?? NaN);
const rawBQty = Number(rawBBin[0]?.actual_qty ?? NaN);
const finishedQty = Number(finishedBin[0]?.actual_qty ?? NaN);
const expectedRawA = ctx.receiptRawA - ctx.consumeRawA;
const expectedRawB = ctx.receiptRawB - ctx.consumeRawB;
const text = JSON.stringify({ rawABin, rawBBin, finishedBin, sleRows, receipt: { name: receipt.name, docstatus: receipt.docstatus }, repack: { name: repack.name, docstatus: repack.docstatus } });
const securityFindings = ['api key', 'api_secret', 'authorization', 'token ', 'password'].filter(term => text.toLowerCase().includes(term));
const status = Number(receipt.docstatus) === 1 && Number(repack.docstatus) === 1 && rawAQty === expectedRawA && rawBQty === expectedRawB && finishedQty === ctx.finishedQty && sleRows.length >= 3 && securityFindings.length === 0 ? 'passed' : 'failed';
return [{ json: { status, runId: ctx.runId, rawA: $node['Create Repack Raw A Item'].json.name, rawB: $node['Create Repack Raw B Item'].json.name, finishedItem: $node['Create Repack Finished Item'].json.name, rawWarehouse: $node['Create Repack Raw Warehouse'].json.name, finishedWarehouse: $node['Create Repack Finished Warehouse'].json.name, rawReceipt: $node['Create Repack Raw Receipt'].json.name, rawReceiptDocstatus: receipt.docstatus, repackStockEntry: $node['Create Repack Stock Entry'].json.name, repackDocstatus: repack.docstatus, rawAQtyAfterRepack: rawAQty, rawBQtyAfterRepack: rawBQty, finishedQtyAfterRepack: finishedQty, expectedRawAQty: expectedRawA, expectedRawBQty: expectedRawB, repackLedgerRows: sleRows.length, repackLedgerActualQty: sleRows.map(row => ({ item_code: row.item_code, warehouse: row.warehouse, actual_qty: row.actual_qty, qty_after_transaction: row.qty_after_transaction })), securityFindings } }];
